188	// EventsToRegister returns the possible events that may make a Pod
189	// failed by this plugin schedulable.
190	func (pl *DefaultPreemption) EventsToRegister(_ context.Context) ([]fwk.ClusterEventWithHint, error) {
191		if pl.fts.EnableAsyncPreemption {
192			return []fwk.ClusterEventWithHint{
193				// We need to register the event to tell the scheduling queue that the pod could be un-gated after some Pods' deletion.
194				{Event: fwk.ClusterEvent{Resource: fwk.AssignedPod, ActionType: fwk.Delete}, QueueingHintFn: pl.isPodSchedulableAfterAssignedPodDeletion},
195			}, nil
196		}
197	
198		// When the async preemption is disabled, PreEnqueue always returns nil, and hence pods never get rejected by this plugin.
199		return nil, nil
200	}
201	
202	// isPodSchedulableAfterAssignedPodDeletion returns the queueing hint for the pod after the assigned pod deletion event,
203	// which always return Skip.
204	// The default preemption plugin is a bit tricky;
205	// the pods rejected by it are the ones that have run/are running the preemption asynchronously.
206	// And, those pods should always have the other plugins in pInfo.UnschedulablePlugins
207	// which failure will be resolved by the preemption.
208	// The reason why we return Skip here is that the preemption plugin should not make the decision of when to requeueing Pods,
209	// and rather, those plugins should be responsible for that.
210	func (pl *DefaultPreemption) isPodSchedulableAfterAssignedPodDeletion(logger klog.Logger, pod *v1.Pod, oldObj, newObj interface{}) (fwk.QueueingHint, error) {
211		return fwk.QueueSkip, nil
212	}
