214	// calculateNumCandidates returns the number of candidates the FindCandidates
215	// method must produce from dry running based on the constraints given by
216	// <minCandidateNodesPercentage> and <minCandidateNodesAbsolute>. The number of
217	// candidates returned will never be greater than <numNodes>.
218	func (pl *DefaultPreemption) calculateNumCandidates(numNodes int32) int32 {
219		n := (numNodes * pl.args.MinCandidateNodesPercentage) / 100
220		if n < pl.args.MinCandidateNodesAbsolute {
221			n = pl.args.MinCandidateNodesAbsolute
222		}
223		if n > numNodes {
224			n = numNodes
225		}
226		return n
227	}
