239	// This function is not applicable for out-of-tree preemption plugins that exercise
240	// different preemption candidates on the same nominated node.
241	func (pl *DefaultPreemption) CandidatesToVictimsMap(candidates []preemption.Candidate) map[string]*extenderv1.Victims {
242		m := make(map[string]*extenderv1.Victims, len(candidates))
243		for _, c := range candidates {
244			m[c.Name()] = c.Victims()
245		}
246		return m
247	}
