249	// SelectVictimsOnNode finds minimum set of pods on the given node that should be preempted in order to make enough room
250	// for "pod" to be scheduled.
251	func (pl *DefaultPreemption) SelectVictimsOnNode(
252		ctx context.Context,
253		state fwk.CycleState,
254		pod *v1.Pod,
255		nodeInfo fwk.NodeInfo,
256		pdbs []*policy.PodDisruptionBudget) ([]*v1.Pod, int, *fwk.Status) {
257		logger := klog.FromContext(ctx)
258		var potentialVictims []fwk.PodInfo
259		removePod := func(rpi fwk.PodInfo) error {
260			if err := nodeInfo.RemovePod(logger, rpi.GetPod()); err != nil {
261				return err
262			}
263			status := pl.fh.RunPreFilterExtensionRemovePod(ctx, state, pod, rpi, nodeInfo)
264			if !status.IsSuccess() {
265				return status.AsError()
266			}
267			return nil
268		}
269		addPod := func(api fwk.PodInfo) error {
270			nodeInfo.AddPodInfo(api)
271			status := pl.fh.RunPreFilterExtensionAddPod(ctx, state, pod, api, nodeInfo)
272			if !status.IsSuccess() {
273				return status.AsError()
274			}
275			return nil
276		}
277		// As the first step, remove all pods eligible for preemption from the node and
278		// check if the given pod can be scheduled without them present.
279		for _, pi := range nodeInfo.GetPods() {
280			if pl.isPreemptionAllowed(nodeInfo, pi, pod) {
281				potentialVictims = append(potentialVictims, pi)
282			}
283		}
284		for _, pi := range potentialVictims {
285			if err := removePod(pi); err != nil {
286				return nil, 0, fwk.AsStatus(err)
287			}
288		}
289	
290		// No potential victims are found, and so we don't need to evaluate the node again since its state didn't change.
291		if len(potentialVictims) == 0 {
292			return nil, 0, fwk.NewStatus(fwk.UnschedulableAndUnresolvable, "No preemption victims found for incoming pod")
293		}
294	
295		// If the new pod does not fit after removing all the eligible pods,
296		// we are almost done and this node is not suitable for preemption. The only
297		// condition that we could check is if the "pod" is failing to schedule due to
298		// inter-pod affinity to one or more victims, but we have decided not to
299		// support this case for performance reasons. Having affinity to lower
300		// importance (priority) pods is not a recommended configuration anyway.
301		if status := pl.fh.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo); !status.IsSuccess() {
302			return nil, 0, status
303		}
304		var victims []fwk.PodInfo
305		numViolatingVictim := 0
306		// Sort potentialVictims by descending importance, which ensures reprieve of
307		// higher importance pods first.
308		sort.Slice(potentialVictims, func(i, j int) bool {
309			return pl.MoreImportantPod(potentialVictims[i].GetPod(), potentialVictims[j].GetPod())
310		})
311		// Try to reprieve as many pods as possible. We first try to reprieve the PDB
312		// violating victims and then other non-violating ones. In both cases, we start
313		// from the highest importance victims.
314		violatingVictims, nonViolatingVictims := filterPodsWithPDBViolation(potentialVictims, pdbs)
315		reprievePod := func(pi fwk.PodInfo) (bool, error) {
316			if err := addPod(pi); err != nil {
317				return false, err
318			}
319			status := pl.fh.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo)
320			fits := status.IsSuccess()
321			if !fits {
322				if err := removePod(pi); err != nil {
323					return false, err
324				}
325				victims = append(victims, pi)
326				logger.V(5).Info("Pod is a potential preemption victim on node", "pod", klog.KObj(pi.GetPod()), "node", klog.KObj(nodeInfo.Node()))
327			}
328			return fits, nil
329		}
330		for _, p := range violatingVictims {
331			if fits, err := reprievePod(p); err != nil {
332				return nil, 0, fwk.AsStatus(err)
333			} else if !fits {
334				numViolatingVictim++
335			}
336		}
337		// Now we try to reprieve non-violating victims.
338		for _, p := range nonViolatingVictims {
339			if _, err := reprievePod(p); err != nil {
340				return nil, 0, fwk.AsStatus(err)
341			}
342		}
343	
344		// Sort victims after reprieving pods to keep the pods in the victims sorted in order of importance from high to low.
345		if len(violatingVictims) != 0 && len(nonViolatingVictims) != 0 {
346			sort.Slice(victims, func(i, j int) bool { return pl.MoreImportantPod(victims[i].GetPod(), victims[j].GetPod()) })
347		}
348		var victimPods []*v1.Pod
349		for _, pi := range victims {
350			victimPods = append(victimPods, pi.GetPod())
351		}
352		return victimPods, numViolatingVictim, fwk.NewStatus(fwk.Success)
353	}
354	
355	// PodEligibleToPreemptOthers returns one bool and one string. The bool
356	// indicates whether this pod should be considered for preempting other pods or
357	// not. The string includes the reason if this pod isn't eligible.
358	// There're several reasons:
359	//  1. The pod has a preemptionPolicy of Never.
360	//  2. The pod has already preempted other pods and the victims are in their graceful termination period.
361	//     Currently we check the node that is nominated for this pod, and as long as there are
362	//     terminating pods on this node, we don't attempt to preempt more pods.
363	func (pl *DefaultPreemption) PodEligibleToPreemptOthers(_ context.Context, pod *v1.Pod, nominatedNodeStatus *fwk.Status) (bool, string) {
364		if pod.Spec.PreemptionPolicy != nil && *pod.Spec.PreemptionPolicy == v1.PreemptNever {
365			return false, "not eligible due to preemptionPolicy=Never."
366		}
367	
368		nodeInfos := pl.fh.SnapshotSharedLister().NodeInfos()
369		nomNodeName := pod.Status.NominatedNodeName
370		if len(nomNodeName) > 0 {
371			// If the pod's nominated node is considered as UnschedulableAndUnresolvable by the filters,
372			// then the pod should be considered for preempting again.
373			if nominatedNodeStatus.Code() == fwk.UnschedulableAndUnresolvable {
374				return true, ""
375			}
376	
377			if nodeInfo, _ := nodeInfos.Get(nomNodeName); nodeInfo != nil {
378				for _, p := range nodeInfo.GetPods() {
379					if pl.isPreemptionAllowed(nodeInfo, p, pod) && podTerminatingByPreemption(p.GetPod()) {
380						// There is a terminating pod on the nominated node.
381						return false, "not eligible due to a terminating pod on the nominated node."
382					}
383				}
384			}
385		}
386		return true, ""
387	}
