389	// OrderedScoreFuncs returns a list of ordered score functions to select preferable node where victims will be preempted.
390	func (pl *DefaultPreemption) OrderedScoreFuncs(ctx context.Context, nodesToVictims map[string]*extenderv1.Victims) []func(node string) int64 {
391		return nil
392	}
