394	// isPreemptionAllowed returns whether the victim residing on nodeInfo can be preempted by the preemptor
395	func (pl *DefaultPreemption) isPreemptionAllowed(nodeInfo fwk.NodeInfo, victim fwk.PodInfo, preemptor *v1.Pod) bool {
396		// The victim must have lower priority than the preemptor, in addition to any filtering implemented by IsEligiblePod
397		return corev1helpers.PodPriority(victim.GetPod()) < corev1helpers.PodPriority(preemptor) && pl.IsEligiblePod(nodeInfo, victim, preemptor)
398	}
399	
400	// podTerminatingByPreemption returns true if the pod is in the termination state caused by scheduler preemption.
401	func podTerminatingByPreemption(p *v1.Pod) bool {
402		if p.DeletionTimestamp == nil {
403			return false
404		}
405	
406		for _, condition := range p.Status.Conditions {
407			if condition.Type == v1.DisruptionTarget {
408				return condition.Status == v1.ConditionTrue && condition.Reason == v1.PodReasonPreemptionByScheduler
409			}
410		}
411		return false
412	}
413	
414	// filterPodsWithPDBViolation groups the given "pods" into two groups of "violatingPods"
415	// and "nonViolatingPods" based on whether their PDBs will be violated if they are
416	// preempted.
417	// This function is stable and does not change the order of received pods. So, if it
418	// receives a sorted list, grouping will preserve the order of the input list.
419	func filterPodsWithPDBViolation(podInfos []fwk.PodInfo, pdbs []*policy.PodDisruptionBudget) (violatingPodInfos, nonViolatingPodInfos []fwk.PodInfo) {
420		pdbsAllowed := make([]int32, len(pdbs))
421		for i, pdb := range pdbs {
422			pdbsAllowed[i] = pdb.Status.DisruptionsAllowed
423		}
424	
425		for _, podInfo := range podInfos {
426			pod := podInfo.GetPod()
427			pdbForPodIsViolated := false
428			// A pod with no labels will not match any PDB. So, no need to check.
429			if len(pod.Labels) != 0 {
430				for i, pdb := range pdbs {
431					if pdb.Namespace != pod.Namespace {
432						continue
433					}
434					selector, err := metav1.LabelSelectorAsSelector(pdb.Spec.Selector)
435					if err != nil {
436						// This object has an invalid selector, it does not match the pod
437						continue
438					}
439					// A PDB with a nil or empty selector matches nothing.
440					if selector.Empty() || !selector.Matches(labels.Set(pod.Labels)) {
441						continue
442					}
443	
444					// Existing in DisruptedPods means it has been processed in API server,
445					// we don't treat it as a violating case.
446					if _, exist := pdb.Status.DisruptedPods[pod.Name]; exist {
447						continue
448					}
449					// Only decrement the matched pdb when it's not in its <DisruptedPods>;
450					// otherwise we may over-decrement the budget number.
451					pdbsAllowed[i]--
452					// We have found a matching PDB.
453					if pdbsAllowed[i] < 0 {
454						pdbForPodIsViolated = true
455					}
456				}
457			}
458			if pdbForPodIsViolated {
459				violatingPodInfos = append(violatingPodInfos, podInfo)
460			} else {
461				nonViolatingPodInfos = append(nonViolatingPodInfos, podInfo)
462			}
463		}
464		return violatingPodInfos, nonViolatingPodInfos
465	}
