467	// PodGroupPostFilter runs a default preemption for the pod group.
468	func (pl *DefaultPreemption) PodGroupPostFilter(ctx context.Context, pg *schedulingapi.PodGroup, pods []*v1.Pod, pgSchedulingFunc func(ctx context.Context) *fwk.Status) *fwk.Status {
469		return pl.podGroupEvaluator.Preempt(ctx, pg, pods, pgSchedulingFunc)
470	}
