790				return cmpBool(p1Err != nil, p2Err != nil)
791			}
792	
793			// adjust p1, p2 usage relative to the request (if any)
794			p1Disk := p1Usage[diskResource]
795			p2Disk := p2Usage[diskResource]
796			p1Request := v1resource.GetResourceRequestQuantity(p1, v1.ResourceEphemeralStorage)
797			p1Disk.Sub(p1Request)
798			p2Request := v1resource.GetResourceRequestQuantity(p2, v1.ResourceEphemeralStorage)
799			p2Disk.Sub(p2Request)
800			// prioritize evicting the pod which has the larger consumption of disk
801			return p2Disk.Cmp(p1Disk)
802		}
803	}
